import{_ as l,o,c as i,ag as e}from"./chunks/framework.CAXxHpAX.js";const c=JSON.parse('{"title":"第 18 章 应用实例：图片文字识别","description":"","frontmatter":{},"headers":[],"relativePath":"ml/photo-ocr.md","filePath":"ml/photo-ocr.md","lastUpdated":null}'),t={name:"ml/photo-ocr.md"};function p(r,a,h,n,_,d){return o(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="第-18-章-应用实例-图片文字识别" tabindex="-1">第 18 章 应用实例：图片文字识别 <a class="header-anchor" href="#第-18-章-应用实例-图片文字识别" aria-label="Permalink to &quot;第 18 章 应用实例：图片文字识别&quot;">​</a></h1><p>这一章用 Photo OCR 作为完整机器学习系统案例，说明如何拆分系统流程、获取数据，并用上限分析决定优化方向。</p><h2 id="_18-1-问题描述和流程图" tabindex="-1">18.1 问题描述和流程图 <a class="header-anchor" href="#_18-1-问题描述和流程图" aria-label="Permalink to &quot;18.1 问题描述和流程图&quot;">​</a></h2><p>Photo OCR 的目标是从图片中识别文字。</p><p>一个完整流程可以拆成：</p><ol><li>文本检测：找出图片中哪些区域包含文字。</li><li>字符切分：把文字区域切成单个字符。</li><li>字符识别：识别每个字符。</li></ol><p>这种流程图有助于把复杂系统拆成多个可评估模块。</p><h2 id="_18-2-滑动窗口" tabindex="-1">18.2 滑动窗口 <a class="header-anchor" href="#_18-2-滑动窗口" aria-label="Permalink to &quot;18.2 滑动窗口&quot;">​</a></h2><p>滑动窗口用于在图像中寻找目标区域。</p><p>基本做法：</p><ol><li>固定一个窗口大小。</li><li>在图像上从左到右、从上到下滑动。</li><li>对每个窗口运行分类器。</li><li>判断该窗口是否包含目标。</li></ol><p>如果目标尺寸变化较大，需要使用多个窗口大小。</p><p>滑动窗口也可以用于行人检测、文本检测等任务。</p><h2 id="_18-3-获取大量数据和人工数据" tabindex="-1">18.3 获取大量数据和人工数据 <a class="header-anchor" href="#_18-3-获取大量数据和人工数据" aria-label="Permalink to &quot;18.3 获取大量数据和人工数据&quot;">​</a></h2><p>机器学习系统常常受益于更多数据，但前提是模型和特征有能力利用这些数据。</p><p>获取数据的方式：</p><ul><li>收集真实数据。</li><li>人工标注数据。</li><li>通过已有样本生成合成数据。</li></ul><p>例如字符识别中，可以用不同字体生成大量字符图像，也可以对已有图像做旋转、缩放、扭曲等变换。</p><p>生成人工数据时要注意：合成数据应该接近真实测试场景，否则帮助有限。</p><h2 id="_18-4-上限分析" tabindex="-1">18.4 上限分析 <a class="header-anchor" href="#_18-4-上限分析" aria-label="Permalink to &quot;18.4 上限分析&quot;">​</a></h2><p>上限分析用于决定系统中哪个模块最值得优化。</p><p>做法：</p><ol><li>记录当前完整系统表现。</li><li>人工把某个模块的输出替换成完美结果。</li><li>观察整体性能提升多少。</li><li>提升最大的模块，优先优化。</li></ol><p>例如 Photo OCR 中，可以分别把文本检测、字符切分、字符识别替换成完美输出，比较系统准确率提升。</p><p>上限分析可以避免把时间花在对整体效果帮助很小的模块上。</p>',25)])])}const u=l(t,[["render",p]]);export{c as __pageData,u as default};
